/**
 * Notification model and related types.
 *
 * All notification types, channels, and payloads are defined here.
 * Other agents should add new NotificationType values as needed.
 */

/**
 * Supported notification types — extend this union as new notification
 * scenarios are added.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Supported delivery channels. Each channel has a corresponding adapter
 * implementing the NotificationAdapter interface.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in_app';

/**
 * Lifecycle status of a notification.
 */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * Payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  metadata?: Record<string, unknown>;
}

/**
 * A recorded notification with delivery status.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  status: NotificationStatus;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Base interface for all notification delivery adapters.
 *
 * CONSTRAINT: All notification adapters MUST implement this interface.
 * The NotificationService routes payloads to adapters by channel.
 * Adapters are responsible for the actual delivery mechanism (email,
 * webhook, in-app push, etc.) and must report success/failure.
 *
 * To add a new channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create an adapter implementing this interface in src/adapters/
 * 3. Register it with NotificationService via registerAdapter()
 */

import type { NotificationPayload } from '../models/notification.js';

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface NotificationDeliveryResult {
  success: boolean;
  error?: string;
}

/**
 * Interface that all notification adapters must implement.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: string;

  /**
   * Send a notification through this adapter's channel.
   * Must not throw — return a failure result instead.
   */
  send(payload: NotificationPayload): Promise<NotificationDeliveryResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that logs emails in-memory. Replace the send()
 * implementation with a real email provider (SendGrid, SES, etc.)
 * when ready — the interface stays the same.
 */

import type { NotificationPayload } from '../models/notification.js';
import type {
  NotificationAdapter,
  NotificationDeliveryResult,
} from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   * Stub implementation — stores the email in-memory and returns success.
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    try {
      this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

      this.sentEmails.push({
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      });

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — orchestrates notification delivery in response to events.
 *
 * ARCHITECTURE: Event-driven via EventBus.
 * - All notifications are triggered by EventBus events (never direct calls).
 * - Delivery is delegated to NotificationAdapter implementations by channel.
 * - Default channel is 'email'; other channels can be registered via registerAdapter().
 *
 * PATTERN:
 *   EventBus event → NotificationService handler → NotificationAdapter.send()
 *
 * CONSTRAINTS:
 * - All notification triggers MUST go through EventBus.emit().
 * - All delivery channels MUST implement NotificationAdapter.
 * - Do NOT call NotificationService methods directly from other services.
 *   Instead, emit an event and let the service handle it.
 *
 * Depends on:
 * - EventBus (event system) for receiving ALL events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type {
  Notification,
  NotificationPayload,
  NotificationType,
  NotificationChannel,
} from '../models/notification.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. For testing only. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<string, NotificationAdapter> = new Map();
  private defaultChannel: NotificationChannel = 'email';

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Adapters must implement the NotificationAdapter interface.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
  }

  /**
   * Register event handlers for notification triggers.
   * All handlers subscribe via EventBus — no other subscription mechanism.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: this.defaultChannel,
      notificationType: 'order_confirmation',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: this.defaultChannel,
      notificationType: 'order_status_update',
    });
  }

  /**
   * Send a notification via the appropriate adapter (or store in-memory if
   * no adapter is registered for the channel).
   */
  private sendNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      notificationType: payload.notificationType,
      status: 'pending',
      sentAt: new Date(),
      metadata: payload.metadata,
    };

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      adapter.send(payload).then((result) => {
        notification.status = result.success ? 'sent' : 'failed';
        if (!result.success) {
          this.logger.error(
            `Adapter delivery failed for ${notification.id}: ${result.error ?? 'unknown'}`,
          );
        }
      });
    } else {
      // No adapter registered — mark as sent (in-memory fallback).
      notification.status = 'sent';
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all recorded notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of recorded notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

